  mode: exports_external.enum(["mul", "it", "mulit"]).describe("[REQUIRED] Orchestration mode. mul=parallel specialists+aggregate, it=generate→critique loop, mulit=mul Phase1 then it Phase2 chained."),
  file_paths: exports_external.array(exports_external.string()).optional().describe("Optional: Local UTF-8 text file paths. The MCP server reads these files server-side; Claude does NOT need to read them. Binary files are not supported."),
  roles: exports_external.array(exports_external.string()).optional().default(["analyst", "architect", "developer", "reviewer", "critic"]).describe('Optional: Specialist agent roles for Phase1 (mul/mulit). Defaults: ["analyst","architect","developer","reviewer","critic"].'),
  max_iterations: numberLike.pipe(exports_external.number().int().min(0).max(10)).optional().default(2).describe("Optional: Number of critic→generator iterations for it/mulit. Default: 2. 0=skip loop."),
  intermediate_results: booleanLike.optional().default(false).describe("Optional: If true, returns structured output including each agent's individual output. Default: false."),
