async function buildFileContext(filePaths) {
  const parts = await Promise.all(filePaths.map(async (fp) => {
    const content = await fs6.readFile(fp, "utf-8");
    const name = path5.basename(fp);
    return `--- File: ${name} (${fp}) ---
${content}`;
  }));
  return parts.join(`

`);
}
async function runPhase1Agents(fullTask, args) {
  const roles = args.roles ?? ["analyst", "architect", "developer", "reviewer", "critic"];
  const serviceTier = resolveServiceTier(args.service_tier);
  const settled = await Promise.allSettled(roles.map(async (role) => {
    const start = Date.now();
    const { text } = await geminiChat(fullTask, {
      model: args.model,
      systemInstruction: `You are a ${role}. Apply your expertise to analyze the task and provide your perspective.`,
      temperature: 0.7,
      thinkingLevel: args.thinking_level,
      toolName: "gemini_team",
      serviceTier
    });
    return { role, output: text, durationMs: Date.now() - start };
  }));
  const results = [];
  const failedRoles = [];
  for (let i2 = 0;i2 < settled.length; i2++) {
    const item = settled[i2];
    const role = roles[i2] ?? `role_${i2}`;
    if (item?.status === "fulfilled") {
      results.push(item.value);
    } else {
      const reason = item?.status === "rejected" ? String(item.reason) : "unknown error";
      failedRoles.push(role);
      results.push({ role, output: "", durationMs: 0, error: reason });
    }
  }
  const successCount = results.filter((r2) => !r2.error).length;
  if (successCount === 0) {
    const lastError = results[results.length - 1]?.error ?? "all agents failed";
    throw new Error(`gemini_team: All specialist agents failed. Last error: ${lastError}`);
  }
  return { results, failedRoles };
}
async function aggregatePhase1(agentResults, task, args) {
  const successResults = agentResults.filter((r2) => !r2.error);
  const combined = successResults.map((r2) => `--- ${r2.role.toUpperCase()} ---
${r2.output}`).join(`

`);
  const aggregationPrompt = `${combined}

--- Original Task ---
${task}`;
  const serviceTier = resolveServiceTier(args.service_tier);
  const { text } = await geminiChat(aggregationPrompt, {
    model: args.model,
    systemInstruction: "You are a coordinator. Synthesize the multiple specialist perspectives above into a unified recommendation. " + "Identify consensus and explicitly flag any unresolved conflicts with each side's rationale.",
    temperature: 0.5,
    thinkingLevel: args.thinking_level,
    toolName: "gemini_team",
    serviceTier
  });
  return text;
}
async function runMul(fullTask, args) {
  const { results, failedRoles } = await runPhase1Agents(fullTask, args);
  const text = await aggregatePhase1(results, fullTask, args);
  return { text, agentResults: results, failedRoles };
}
async function generateInitialDraft(fullTask, args) {
  const serviceTier = resolveServiceTier(args.service_tier);
  const { text } = await geminiChat(fullTask, {
    model: args.model,
    systemInstruction: "You are a writer. Generate an initial draft based on the following task description.",
    temperature: 0.7,
    thinkingLevel: args.thinking_level,
    toolName: "gemini_team",
    serviceTier
  });
  return text;
}
function extractRubricScore(critiqueText) {
  const match2 = critiqueText.match(/(?:overall|average|score)[^\d]*(\d+(?:\.\d+)?)\s*(?:\/\s*5)?/i);
  if (match2?.[1]) {
    const score = parseFloat(match2[1]);
    return isNaN(score) ? undefined : score;
  }
  return;
}
async function runItLoop(initialDraft, fullTask, args) {
  const serviceTier = resolveServiceTier(args.service_tier);
  let draft = initialDraft;
  let actualIterations = 0;
  for (let i2 = 1;i2 <= args.max_iterations; i2++) {
    const { text: critique } = await geminiChat(`--- Draft ---
${draft}

--- Original Task ---
${fullTask}`, {
      model: args.model,
      systemInstruction: "You are a critic. Evaluate the draft against the task requirements. " + "Provide specific, actionable feedback. " + "End your response with: 'Overall score: X/5' where X is an average quality score (1-5).",
      temperature: 0.3,
      thinkingLevel: args.thinking_level,
      toolName: "gemini_team",
      serviceTier
    });
    actualIterations = i2;
    const score = extractRubricScore(critique);
    if (score !== undefined && score >= 4) {
      break;
    }
    if (i2 < args.max_iterations) {
      const { text: improved } = await geminiChat(`--- Current Draft ---
${draft}

--- Critic Feedback ---
${critique}

--- Original Task ---
${fullTask}`, {
        model: args.model,
        systemInstruction: "You are a writer. Improve the draft based on the critic's feedback while preserving its strengths.",
        temperature: 0.7,
        thinkingLevel: args.thinking_level,
        toolName: "gemini_team",
        serviceTier
      });
      draft = improved;
    }
  }
  return { text: draft, iterations: actualIterations };
}
async function runIt(fullTask, args) {
  if (args.max_iterations === 0) {
    const text = await generateInitialDraft(fullTask, args);
    return { text, iterations: 0 };
  }
  const initialDraft = await generateInitialDraft(fullTask, args);
  return runItLoop(initialDraft, fullTask, args);
}
async function runMulit(fullTask, originalTask, args) {
  const roles = args.roles ?? ["analyst", "architect", "developer", "reviewer", "critic"];
  const serviceTier = resolveServiceTier(args.service_tier);
  const phase1Promises = roles.map(async (role) => {
    const start = Date.now();
    const { text: text2 } = await geminiChat(fullTask, {
      model: args.model,
      systemInstruction: `You are a ${role}. Apply your expertise to analyze the task and provide your perspective.`,
      temperature: 0.7,
      thinkingLevel: args.thinking_level,
      toolName: "gemini_team",
      serviceTier
    });
    return { role, output: text2, durationMs: Date.now() - start };
  });
  const speculativePromise = geminiChat(originalTask, {
    model: args.model,
    systemInstruction: "You are a writer. Generate an initial draft based on the following task description.",
    temperature: 0.7,
    thinkingLevel: args.thinking_level,
    toolName: "gemini_team",
    serviceTier
  }).then((r2) => r2.text);
  const [settledPhase1, speculativeDraft] = await Promise.all([
    Promise.allSettled(phase1Promises),
    speculativePromise
  ]);
  const agentResults = [];
  const failedRoles = [];
  for (let i2 = 0;i2 < settledPhase1.length; i2++) {
    const item = settledPhase1[i2];
    const role = roles[i2] ?? `role_${i2}`;
    if (item?.status === "fulfilled") {
      agentResults.push(item.value);
    } else {
      const reason = item?.status === "rejected" ? String(item.reason) : "unknown error";
      failedRoles.push(role);
      agentResults.push({ role, output: "", durationMs: 0, error: reason });
    }
  }
  const successCount = agentResults.filter((r2) => !r2.error).length;
  if (successCount === 0) {
    throw new Error("gemini_team: All Phase1 specialist agents failed.");
  }
  const aggregatedContext = await aggregatePhase1(agentResults, fullTask, args);
  const { text, iterations } = await runItLoop(speculativeDraft, `${aggregatedContext}

--- Original Task ---
${originalTask}`, args);
  return { text, agentResults, failedRoles, iterations };
}
async function handleTeam(args) {
  const startMs = Date.now();
  const fileContext = args.file_paths && args.file_paths.length > 0 ? await buildFileContext(args.file_paths) : "";
  const fullTask = fileContext ? `${fileContext}

--- Task ---
${args.task}` : args.task;
  const fileCount = args.file_paths?.length ?? 0;
  if (args.mode === "mul") {
    const { text: text2, agentResults: agentResults2, failedRoles: failedRoles2 } = await runMul(fullTask, args);
    if (!args.intermediate_results)
      return text2;
    const metadata2 = {
      mode: "mul",
      agentCount: agentResults2.filter((r2) => !r2.error).length,
      iterations: 0,
      fileCount,
      failedAgents: failedRoles2,
      totalDurationMs: Date.now() - startMs
    };
    return { text: text2, structured: { phases: agentResults2, metadata: metadata2 } };
  }
  if (args.mode === "it") {
    const { text: text2, iterations: iterations2 } = await runIt(fullTask, args);
    if (!args.intermediate_results)
      return text2;
    const metadata2 = {
      mode: "it",
      agentCount: 0,
      iterations: iterations2,
      fileCount,
      failedAgents: [],
      totalDurationMs: Date.now() - startMs
    };
    return { text: text2, structured: { phases: [], metadata: metadata2 } };
  }
  const { text, agentResults, failedRoles, iterations } = await runMulit(fullTask, args.task, args);
  if (!args.intermediate_results)
    return text;
  const metadata = {
    mode: "mulit",
    agentCount: agentResults.filter((r2) => !r2.error).length,
    iterations,
    fileCount,
    failedAgents: failedRoles,
    totalDurationMs: Date.now() - startMs
  };
  return { text, structured: { phases: agentResults, metadata } };
}

