// src/utils/errors.ts
function handleApiError(error51, toolName = "unknown") {
  if (error51 instanceof Error) {
    const apiErr = error51;
    const status = apiErr.status ?? apiErr.statusCode;
    switch (status) {
      case 400:
        return `Error: The request is invalid. Please check the parameters. (${error51.message})`;
      case 401:
        return "Error: Authentication failed. Please check the API key.";
      case 403:
        return "Error: Access denied. Please check the credentials or scopes.";
      case 404:
        return "Error: Resource not found. Please check the ID or path.";
      case 429:
        return "Error: Rate limit reached. Please wait a moment and try again.";
      case 500:
      case 502:
      case 503:
        return `Error: A server error occurred (status: ${status}). Please wait a moment and try again.`;
      default:
        if (error51.message.includes("timed out")) {
          return `Error: The request timed out. The operation may be too complex. (${error51.message})`;
        }
        logger.error({ err: error51, toolName }, "Unexpected error during tool execution");
        return `Error: ${error51.message}`;
    }
  }
  return `Error: An unexpected error occurred: ${String(error51)}`;
}

// src/constants.ts
var CHARACTER_LIMIT = 25000;
var TRUNCATION_SUFFIX = `

... (Response truncated because it exceeded the limit. Add filter conditions or use a more specific query.)`;
function truncate(text) {
  if (text.length <= CHARACTER_LIMIT)
    return text;
  return text.slice(0, CHARACTER_LIMIT) + TRUNCATION_SUFFIX;
}

// src/server.ts
function createMcpServer(opts) {
  const server = new McpServer({ name: opts.name, version: opts.version });
  for (const tool of allTools) {
    server.registerTool(tool.name, {
      title: tool.title,
      description: tool.description,
      inputSchema: tool.schema,
      annotations: tool.annotations
    }, async (args, extra) => {
      try {
        const progressToken = extra._meta?.progressToken;
        const progress = progressToken !== undefined && progressToken !== null ? async (current, total, message) => {
          await extra.sendNotification({
            method: "notifications/progress",
            params: {
              progressToken,
              progress: current,
              ...total !== undefined ? { total } : {},
              ...message !== undefined ? { message } : {}
            }
          });
        } : undefined;
        const ret = await tool.handler(args, progress ? { progress } : {});
        const text = typeof ret === "string" ? ret : ret.text;
        const structured = typeof ret === "string" ? undefined : ret.structured;
        return {
          content: [{ type: "text", text: truncate(text) }],
          ...structured ? { structuredContent: structured } : {}
        };
      } catch (error51) {
        const message = handleApiError(error51, tool.name);
        return {
          content: [{ type: "text", text: message }],
          isError: true
        };
      }
    });
  }
  return server;
}
